INSERT INTO `wp_postmeta` VALUES (379,63,'bio','I''m an informatics student based in Bandung, currently in my 6th semester. I love building beautiful and functional digital experiences.                                                                                                                                                                                                                                                                                                                                                                                                                                                                                When I''m not studying or coding, you can probably find me nerding out over something — deep in a book, way too invested in a fandom, or falling down a research rabbit hole about something completely unrelated to my major. I believe the internet is one of the best places to find people who get just as excited about niche things as you do.INSERT INTO `wp_postmeta` VALUES (380,63,'_bio','field_6a46fec595482');
