INSERT INTO `wp_posts` VALUES (16,1,'2026-07-01 23:54:12','2026-07-01 23:54:12','<!-- wp:paragraph -->\n<p>Scraped and analyzed Instax camera listings from Tokopedia, then visualized pricing and sales trends with Tableau.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p></p>\n<!-- /wp:paragraph -->','Instax Sales Dashboard (Tokopedia Scraper)','','publish','closed','closed','','instax-sales-dashboard-tokopedia-scraper','','','2026-07-02 00:21:36','2026-07-02 00:21:36','',0,'http://localhost:8881/?post_type=project&#038;p=16',0,'project','',0);
