INSERT INTO `wp_posts` VALUES (39,1,'2026-07-03 00:24:06','2026-07-03 00:24:06','<!-- wp:group {"metadata":{"patternName":"twentytwentyfive/cta-centered-heading","name":"Centered heading","description":"A hero with a centered heading, paragraph and button.","categories":["call-to-action"]},"align":"full","style":{"spacing":{"padding":{"right":"var:preset|spacing|40","left":"var:preset|spacing|40","top":"var:preset|spacing|70","bottom":"var:preset|spacing|70"},"margin":{"top":"0","bottom":"0"}},"dimensions":{"minHeight":"0vh"}},"layout":{"type":"constrained"}} -->\n<div class="wp-block-group alignfull" style="min-height:0vh;margin-top:0;margin-bottom:0;padding-top:var(--wp--preset--spacing--70);padding-right:var(--wp--preset--spacing--40);padding-bottom:var(--wp--preset--spacing--70);padding-left:var(--wp--preset--spacing--40)"><!-- wp:group {"style":{"spacing":{"blockGap":"var:preset|spacing|40"}},"layout":{"type":"constrained"}} -->\n<div class="wp-block-group"><!-- wp:heading {"style":{"spacing":{"margin":{"right":"0","left":"0"},"padding":{"right":"0","left":"0"}},"typography":{"textAlign":"center"}},"fontSize":"xx-large"} -->\n<h2 class="wp-block-heading has-text-align-center has-xx-large-font-size" style="margin-right:0;margin-left:0;padding-right:0;padding-left:0">Tell your story</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {"style":{"typography":{"textAlign":"center"}}} -->\n<p class="has-text-align-center">Like flowers that bloom in unexpected places, every story unfolds with beauty and resilience, revealing hidden wonders.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:buttons {"layout":{"type":"flex","justifyContent":"center"}} -->\n<div class="wp-block-buttons"><!-- wp:button -->\n<div class="wp-block-button"><a class="wp-block-button__link wp-element-button">Learn more</a></div>\n<!-- /wp:button --></div>\n<!-- /wp:buttons --></div>\n<!-- /wp:group --></div>\n<!-- /wp:group -->\n\n<!-- wp:group {"metadata":{"patternName":"twentytwentyfive/overlapped-images","name":"Overlapping images and paragraph on right","description":"A section with overlapping images, and a description.","categories":["about","featured"]},"align":"full","className":"is-style-section-1","style":{"spacing":{"padding":{"top":"var:preset|spacing|80","bottom":"var:preset|spacing|80"},"margin":{"top":"0","bottom":"0"}}},"layout":{"type":"constrained"}} -->\n<div class="wp-block-group alignfull is-style-section-1" style="margin-top:0;margin-bottom:0;padding-top:var(--wp--preset--spacing--80);padding-bottom:var(--wp--preset--spacing--80)"><!-- wp:columns {"align":"wide","style":{"spacing":{"blockGap":{"top":"var:preset|spacing|80","left":"var:preset|spacing|80"}}}} -->\n<div class="wp-block-columns alignwide"><!-- wp:column {"width":"45%","style":{"spacing":{"padding":{"right":"var:preset|spacing|50"}}}} -->\n<div class="wp-block-column" style="padding-right:var(--wp--preset--spacing--50);flex-basis:45%"><!-- wp:image {"sizeSlug":"full"} -->\n<figure class="wp-block-image size-full"><img src="http://localhost:8881/wp-content/themes/twentytwentyfive/assets/images/red-hibiscus-closeup.webp" alt="Photography close up of a red flower."/></figure>\n<!-- /wp:image -->\n\n<!-- wp:group {"style":{"spacing":{"margin":{"top":"-12vw"}}},"layout":{"type":"constrained"}} -->\n<div class="wp-block-group" style="margin-top:-12vw"><!-- wp:image {"width":"202px","sizeSlug":"full","align":"right","className":"is-resized","style":{"spacing":{"margin":{"right":"-5vw","left":"-5vw"}}}} -->\n<figure class="wp-block-image alignright size-full is-resized" style="margin-right:-5vw;margin-left:-5vw"><img src="http://localhost:8881/wp-content/themes/twentytwentyfive/assets/images/grid-flower-2.webp" alt="Black and white photography close up of a flower." style="width:202px"/></figure>\n<!-- /wp:image --></div>\n<!-- /wp:group --></div>\n<!-- /wp:column -->\n\n<!-- wp:column {"verticalAlignment":"center","width":"50%","style":{"spacing":{"padding":{"left":"0","right":"0"}}}} -->\n<div class="wp-block-column is-vertically-aligned-center" style="padding-right:0;padding-left:0;flex-basis:50%"><!-- wp:group {"layout":{"type":"flex","orientation":"vertical"}} -->\n<div class="wp-block-group"><!-- wp:heading {"className":"is-style-text-annotation"} -->\n<h2 class="wp-block-heading is-style-text-annotation">About Us</h2>\n<!-- /wp:heading --></div>\n<!-- /wp:group -->\n\n<!-- wp:paragraph {"className":"is-style-text-subtitle"} -->\n<p class="is-style-text-subtitle">\n			<strong>Fleurs</strong> is a flower delivery and subscription business. Based in the EU, our mission is not only to deliver stunning flower arrangements across but also foster knowledge and enthusiasm on the beautiful gift of nature: flowers.			</p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:column --></div>\n<!-- /wp:columns --></div>\n<!-- /wp:group -->\n\n<!-- wp:group {"metadata":{"patternName":"twentytwentyfive/services-3-col","name":"Services, 3 columns","description":"Three columns with images and text to showcase services.","categories":["call-to-action","banner","services"]},"align":"full","style":{"spacing":{"padding":{"top":"var:preset|spacing|50","bottom":"var:preset|spacing|50"},"blockGap":"var:preset|spacing|50","margin":{"top":"0","bottom":"0"}}},"layout":{"type":"constrained"}} -->\n<div class="wp-block-group alignfull" style="margin-top:0;margin-bottom:0;padding-top:var(--wp--preset--spacing--50);padding-bottom:var(--wp--preset--spacing--50)"><!-- wp:heading {"align":"wide"} -->\n<h2 class="wp-block-heading alignwide">Our services</h2>\n<!-- /wp:heading -->\n\n<!-- wp:columns {"align":"wide"} -->\n<div class="wp-block-columns alignwide"><!-- wp:column -->\n<div class="wp-block-column"><!-- wp:image {"aspectRatio":"4/3","scale":"cover","sizeSlug":"full","style":{"spacing":{"margin":{"bottom":"24px"}}}} -->\n<figure class="wp-block-image size-full" style="margin-bottom:24px"><img src="http://localhost:8881/wp-content/themes/twentytwentyfive/assets/images/campanula-alliariifolia-flower.webp" alt="Image for service" style="aspect-ratio:4/3;object-fit:cover"/></figure>\n<!-- /wp:image -->\n\n<!-- wp:heading {"level":3} -->\n<h3 class="wp-block-heading">Collect</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {"fontSize":"medium"} -->\n<p class="has-medium-font-size">Like flowers that bloom in unexpected places, every story unfolds with beauty and resilience</p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:column -->\n\n<!-- wp:column -->\n<div class="wp-block-column"><!-- wp:image {"aspectRatio":"4/3","scale":"cover","sizeSlug":"full","style":{"spacing":{"margin":{"bottom":"24px"}}}} -->\n<figure class="wp-block-image size-full" style="margin-bottom:24px"><img src="http://localhost:8881/wp-content/themes/twentytwentyfive/assets/images/delphinium-flowers.webp" alt="Image for service" style="aspect-ratio:4/3;object-fit:cover"/></figure>\n<!-- /wp:image -->\n\n<!-- wp:heading {"level":3} -->\n<h3 class="wp-block-heading">Assemble</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {"fontSize":"medium"} -->\n<p class="has-medium-font-size">Like flowers that bloom in unexpected places, every story unfolds with beauty and resilience</p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:column -->\n\n<!-- wp:column -->\n<div class="wp-block-column"><!-- wp:image {"aspectRatio":"4/3","scale":"cover","sizeSlug":"full","style":{"spacing":{"margin":{"bottom":"24px"}}}} -->\n<figure class="wp-block-image size-full" style="margin-bottom:24px"><img src="http://localhost:8881/wp-content/themes/twentytwentyfive/assets/images/star-thristle-flower.webp" alt="Image for service" style="aspect-ratio:4/3;object-fit:cover"/></figure>\n<!-- /wp:image -->\n\n<!-- wp:heading {"level":3} -->\n<h3 class="wp-block-heading">Deliver</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {"fontSize":"medium"} -->\n<p class="has-medium-font-size">Like flowers that bloom in unexpected places, every story unfolds with beauty and resilience</p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:column --></div