width":100} -->\n<div class="wp-block-button has-custom-width wp-block-button__width-100"><a class="wp-block-button__link wp-element-button">Join</a></div>\n<!-- /wp:button --></div>\n<!-- /wp:buttons --></div>\n<!-- /wp:column -->\n\n<!-- wp:column {"style":{"spacing":{"padding":{"top":"var:preset|spacing|50","right":"var:preset|spacing|50","bottom":"var:preset|spacing|50","left":"var:preset|spacing|50"}},"border":{"width":"1px","color":"var:preset|color|accent-6","radius":"10px"}},"layout":{"type":"default"}} -->\n<div class="wp-block-column has-border-color" style="border-color:var(--wp--preset--color--accent-6);border-width:1px;border-radius:10px;padding-top:var(--wp--preset--spacing--50);padding-right:var(--wp--preset--spacing--50);padding-bottom:var(--wp--preset--spacing--50);padding-left:var(--wp--preset--spacing--50)"><!-- wp:heading {"level":3,"anchor":"single"} -->\n<h3 id="single" class="wp-block-heading">Single</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {"fontSize":"large"} -->\n<p class="has-large-font-size">20€/month</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list {"className":"is-style-checkmark-list","style":{"spacing":{"padding":{"bottom":"var:preset|spacing|20","left":"var:preset|spacing|20"}}},"fontSize":"small"} -->\n<ul style="padding-bottom:var(--wp--preset--spacing--20);padding-left:var(--wp--preset--spacing--20)" class="wp-block-list is-style-checkmark-list has-small-font-size"><!-- wp:list-item -->\n<li>Get access to our paid articles and weekly newsletter.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Join our IRL events.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Get a free tote bag.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>An elegant addition of home decor collection.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Join our forums.</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:buttons {"layout":{"type":"flex","justifyContent":"center"}} -->\n<div class="wp-block-buttons"><!-- wp:button {"width":100} -->\n<div class="wp-block-button has-custom-width wp-block-button__width-100"><a class="wp-block-button__link wp-element-button">Join</a></div>\n<!-- /wp:button --></div>\n<!-- /wp:buttons --></div>\n<!-- /wp:column --></div>\n<!-- /wp:columns --></div>\n<!-- /wp:group -->\n\n<!-- wp:group {"tagName":"aside","metadata":{"patternName":"twentytwentyfive/cta-newsletter","name":"Newsletter sign-up","categories":["call-to-action"]},"align":"full","className":"is-style-section-3","style":{"spacing":{"padding":{"right":"var:preset|spacing|50","left":"var:preset|spacing|50","top":"var:preset|spacing|50","bottom":"var:preset|spacing|50"},"margin":{"top":"0","bottom":"0"}},"dimensions":{"minHeight":""}},"layout":{"type":"constrained","contentSize":"800px"}} -->\n<aside class="wp-block-group alignfull is-style-section-3" style="margin-top:0;margin-bottom:0;padding-top:var(--wp--preset--spacing--50);padding-right:var(--wp--preset--spacing--50);padding-bottom:var(--wp--preset--spacing--50);padding-left:var(--wp--preset--spacing--50)"><!-- wp:group {"style":{"dimensions":{"minHeight":"360px"},"spacing":{"margin":{"top":"0","bottom":"0"}}},"layout":{"type":"flex","orientation":"vertical","verticalAlignment":"center","justifyContent":"center"}} -->\n<div class="wp-block-group" style="min-height:360px;margin-top:0;margin-bottom:0"><!-- wp:heading {"style":{"typography":{"textAlign":"center"}},"fontSize":"xx-large"} -->\n<h2 class="wp-block-heading has-text-align-center has-xx-large-font-size">Sign up to get daily stories</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {"className":"is-style-text-subtitle","style":{"typography":{"textAlign":"center"}}} -->\n<p class="has-text-align-center is-style-text-subtitle">Get access to a curated collection of moments in time featuring photographs from historical relevance.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:spacer {"height":"0px","style":{"layout":{"flexSize":"20px","selfStretch":"fixed"}}} -->\n<div style="height:0px" aria-hidden="true" class="wp-block-spacer"></div>\n<!-- /wp:spacer -->\n\n<!-- wp:buttons {"layout":{"type":"flex","justifyContent":"center"}} -->\n<div class="wp-block-buttons"><!-- wp:button {"style":{"typography":{"textAlign":"center"}}} -->\n<div class="wp-block-button"><a class="wp-block-button__link has-text-align-center wp-element-button">Subscribe</a></div>\n<!-- /wp:button --></div>\n<!-- /wp:buttons --></div>\n<!-- /wp:group --></aside>\n<!-- /wp:group -->','About','','inherit','closed','closed','','39-revision-v1','','','2026-07-03 01:55:44','2026-07-03 01:55:44','',39,'http://localhost:8881/?p=72',0,'revision','',0);
